import android.content.Intent
import android.graphics.BitmapFactory
import android.net.Uri
import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class ShareReceiverActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_receiver)

        handleIntent(intent)
    }

    private fun handleIntent(intent: Intent) {
        val action = intent.action
        val type = intent.type

        if (Intent.ACTION_SEND == action && type != null) {
            when {
                "text/plain" == type -> {
                    handleSendText(intent)
                }
                type.startsWith("image/") -> {
                    handleSendImage(intent)
                }
                else -> {
                    // Handle other types
                    Toast.makeText(this, "Unsupported content type", Toast.LENGTH_SHORT).show()
                }
            }
        } else if (Intent.ACTION_SEND_MULTIPLE == action && type != null) {
            when {
                type.startsWith("image/") -> {
                    handleSendMultipleImages(intent)
                }
                else -> {
                    // Handle other types
                    Toast.makeText(this, "Unsupported content type", Toast.LENGTH_SHORT).show()
                }
            }
        }
    }

    private fun handleSendText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        if (sharedText != null) {
            // Process the received text
            Toast.makeText(this, "Received URL: $sharedText", Toast.LENGTH_LONG).show()
        }
    }

    private fun handleSendImage(intent: Intent) {
        val imageUri: Uri? = intent.getParcelableExtra(Intent.EXTRA_STREAM)
        if (imageUri != null) {
            // Process the received image
            val bitmap = BitmapFactory.decodeStream(contentResolver.openInputStream(imageUri))
            Toast.makeText(this, "Received image", Toast.LENGTH_SHORT).show()
            // Further processing can be done with the bitmap
        }
    }

    private fun handleSendMultipleImages(intent: Intent) {
        intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)?.let { uris ->
            for (uri in uris) {
                val bitmap = BitmapFactory.decodeStream(contentResolver.openInputStream(uri))
                Toast.makeText(this, "Received image", Toast.LENGTH_SHORT).show()
                // Further processing can be done with each bitmap
            }
        }
    }
}